	t.Chdir(dir)

	s := &ManualCommitStrategy{}
	sessionID := "2026-02-09-multi-checkpoint"

	// Create metadata directory
	metadataDir := ".entire/metadata/" + sessionID
	metadataDirAbs := filepath.Join(dir, metadataDir)
	if err := os.MkdirAll(metadataDirAbs, 0o755); err != nil {
		t.Fatalf("failed to create metadata dir: %v", err)
	}

	transcriptPath := filepath.Join(metadataDirAbs, paths.TranscriptFileName)

	// CHECKPOINT 1: Initial work with 2 messages (1 gemini message with tokens)
	checkpoint1Transcript := `{
		"sessionId": "multi-test",
		"messages": [
			{
				"type": "user",
				"content": "Add a main function"
			},
			{
				"type": "gemini",
				"content": "I'll add a main function",
				"tokens": {
					"input": 100,
					"output": 50,
					"cached": 20
				}
			}
		]
	}`

	if err := os.WriteFile(transcriptPath, []byte(checkpoint1Transcript), 0o644); err != nil {
		t.Fatalf("failed to write transcript: %v", err)
	}

	// Modify file for checkpoint 1
	if err := os.WriteFile(testFile, []byte("package main\n\nfunc main() {}\n"), 0o644); err != nil {
		t.Fatalf("failed to modify file: %v", err)
	}

	// Save checkpoint 1
	err = s.SaveChanges(StepContext{
		SessionID:      sessionID,
		ModifiedFiles:  []string{"code.go"},
		NewFiles:       []string{},
		DeletedFiles:   []string{},
		MetadataDir:    metadataDir,
		MetadataDirAbs: metadataDirAbs,
		CommitMessage:  "Checkpoint 1",
		AuthorName:     "Gemini CLI",
		AuthorEmail:    "gemini@test.com",
		AgentType:      agent.AgentTypeGemini,
	})
	if err != nil {
		t.Fatalf("SaveChanges() checkpoint 1 error = %v", err)
	}

	// Load and verify state after checkpoint 1
	state, err := s.loadSessionState(sessionID)
	if err != nil {
		t.Fatalf("loadSessionState() error = %v", err)
	}
	if state.CheckpointTranscriptStart != 0 {
		t.Errorf("CheckpointTranscriptStart after checkpoint 1 = %d, want 0", state.CheckpointTranscriptStart)
	}

	// CHECKPOINT 2: Add more messages to transcript (simulating continued session)
	// This adds 2 more messages (indices 2 and 3), with new token counts
	checkpoint2Transcript := `{
		"sessionId": "multi-test",
		"messages": [
			{
				"type": "user",
				"content": "Add a main function"
			},
			{
				"type": "gemini",
				"content": "I'll add a main function",
				"tokens": {
					"input": 100,
					"output": 50,
					"cached": 20
				}
			},
			{
				"type": "user",
				"content": "Now add error handling"
			},
			{
				"type": "gemini",
				"content": "I'll add error handling",
				"tokens": {
					"input": 200,
					"output": 75,
					"cached": 30
				}
			}
		]
	}`

	if err := os.WriteFile(transcriptPath, []byte(checkpoint2Transcript), 0o644); err != nil {
		t.Fatalf("failed to update transcript: %v", err)
	}

	// Modify file for checkpoint 2
	if err := os.WriteFile(testFile, []byte("package main\n\nfunc main() {\n\tif err := run(); err != nil {\n\t\tpanic(err)\n\t}\n}\n"), 0o644); err != nil {
		t.Fatalf("failed to modify file: %v", err)
	}

	// Before checkpoint 2, manually update CheckpointTranscriptStart to simulate
	// what would happen after condensing checkpoint 1
	state.CheckpointTranscriptStart = 2 // Start from message index 2 (the second user prompt)
	state.StepCount = 1                 // Set to 1 (will be incremented to 2 by SaveChanges)
	if err := s.saveSessionState(state); err != nil {
		t.Fatalf("failed to update session state: %v", err)
	}

	// Save checkpoint 2
	err = s.SaveChanges(StepContext{
		SessionID:      sessionID,
		ModifiedFiles:  []string{"code.go"},
		NewFiles:       []string{},
		DeletedFiles:   []string{},
		MetadataDir:    metadataDir,
		MetadataDirAbs: metadataDirAbs,
		CommitMessage:  "Checkpoint 2",
		AuthorName:     "Gemini CLI",
		AuthorEmail:    "gemini@test.com",
		AgentType:      agent.AgentTypeGemini,
	})
	if err != nil {
		t.Fatalf("SaveChanges() checkpoint 2 error = %v", err)
	}

	// Reload state to get updated values
	state, err = s.loadSessionState(sessionID)
	if err != nil {
		t.Fatalf("loadSessionState() error = %v", err)
	}

	// Condense the session - this should calculate token usage ONLY from message index 2 onwards
	checkpointID := id.MustCheckpointID("ddeeff998877")
	result, err := s.CondenseSession(repo, checkpointID, state, nil)
	if err != nil {
		t.Fatalf("CondenseSession() error = %v", err)
	}

	// Verify result
	if result.CheckpointsCount != 2 {
		t.Errorf("CheckpointsCount = %d, want 2", result.CheckpointsCount)
	}
	if result.TotalTranscriptLines != 4 {
		t.Errorf("TotalTranscriptLines = %d, want 4 (4 messages in Gemini format)", result.TotalTranscriptLines)
	}

	// Read condensed metadata
	store := checkpoint.NewGitStore(repo)
	content, err := store.ReadLatestSessionContent(t.Context(), checkpointID)
	if err != nil {
		t.Fatalf("ReadLatestSessionContent() error = %v", err)
	}

	// CRITICAL VERIFICATION: Token usage should ONLY count from message index 2 onwards
	// This means ONLY the second gemini message (indices 2-3), NOT the first one (indices 0-1)
	if content.Metadata.TokenUsage == nil {
		t.Fatal("TokenUsage should not be nil")
	}

	// Expected: Only the second gemini message tokens (input=200, output=75, cached=30)
	// NOT the first gemini message tokens (input=100, output=50, cached=20)
	if content.Metadata.TokenUsage.InputTokens != 200 {
		t.Errorf("InputTokens = %d, want 200 (should only count from checkpoint start, not entire transcript)",
			content.Metadata.TokenUsage.InputTokens)
	}
	if content.Metadata.TokenUsage.OutputTokens != 75 {
		t.Errorf("OutputTokens = %d, want 75 (should only count from checkpoint start, not entire transcript)",
			content.Metadata.TokenUsage.OutputTokens)
	}
	if content.Metadata.TokenUsage.CacheReadTokens != 30 {
		t.Errorf("CacheReadTokens = %d, want 30 (should only count from checkpoint start, not entire transcript)",
			content.Metadata.TokenUsage.CacheReadTokens)
	}
	if content.Metadata.TokenUsage.APICallCount != 1 {
		t.Errorf("APICallCount = %d, want 1 (only one gemini message after checkpoint start)",
			content.Metadata.TokenUsage.APICallCount)
	}

	// Verify the full transcript is stored (all 4 messages)
	if len(content.Transcript) == 0 {
		t.Error("Full transcript should be stored")
	}

	// Verify both prompts are present (even though tokens only count from second prompt)
	if !strings.Contains(content.Prompts, "Add a main function") {
		t.Error("Prompts should contain first prompt")
	}
	if !strings.Contains(content.Prompts, "Now add error handling") {
		t.Error("Prompts should contain second prompt")
	}
}

package strategy

import (
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/paths"
	"github.com/go-git/go-git/v5"
	"github.com/go-git/go-git/v5/plumbing/object"
)

const (
	testTranscript = `{"type":"human","message":{"content":"add function"}}
{"type":"assistant","message":{"content":"adding function"}}
`
	testCheckpoint1Content = "package main\n\nfunc agentFunc() {\n\tprintln(\"agent\")\n}\n"
)

// TestPromptAttribution_UsesWorktreeNotStagingArea tests that attribution calculation
// reads from the worktree (not staging area) to match what WriteTemporary captures.
// This ensures that if a user has both staged and unstaged changes, ALL changes are
// counted in PromptAttribution to match what's in the checkpoint tree.
//
// IMPORTANT: If we read from staging area but checkpoints capture worktree, unstaged
// changes would appear in the checkpoint but not in PromptAttribution, causing them
// to be incorrectly attributed to the agent later.
func TestPromptAttribution_UsesWorktreeNotStagingArea(t *testing.T) {
	dir := t.TempDir()
	repo, err := git.PlainInit(dir, false)
	if err != nil {
		t.Fatalf("failed to init repo: %v", err)
	}

	worktree, err := repo.Worktree()
	if err != nil {
		t.Fatalf("failed to get worktree: %v", err)
	}

	// Create initial commit with a file
	testFile := filepath.Join(dir, "test.go")
	if err := os.WriteFile(testFile, []byte("package main\n"), 0o644); err != nil {
		t.Fatalf("failed to write initial file: %v", err)
	}
	if _, err := worktree.Add("test.go"); err != nil {
		t.Fatalf("failed to stage file: %v", err)
	}
	_, err = worktree.Commit("Initial commit", &git.CommitOptions{
		Author: &object.Signature{Name: "Test", Email: "test@test.com", When: time.Now()},
	})
	if err != nil {
		t.Fatalf("failed to commit: %v", err)
	}

	t.Chdir(dir)

	s := &ManualCommitStrategy{}
	sessionID := "2026-01-23-staging-test"

	// Create metadata directory
	metadataDir := ".entire/metadata/" + sessionID
	metadataDirAbs := filepath.Join(dir, metadataDir)
	if err := os.MkdirAll(metadataDirAbs, 0o755); err != nil {
		t.Fatalf("failed to create metadata dir: %v", err)
	}

	if err := os.WriteFile(filepath.Join(metadataDirAbs, paths.TranscriptFileName), []byte(testTranscript), 0o644); err != nil {
		t.Fatalf("failed to write transcript: %v", err)
	}

	// === PROMPT 1 START: Initialize session ===
	if err := s.InitializeSession(sessionID, "Claude Code", "", ""); err != nil {
		t.Fatalf("InitializeSession() prompt 1 error = %v", err)
	}

	// === CHECKPOINT 1: Agent adds 4 lines ===
	if err := os.WriteFile(testFile, []byte(testCheckpoint1Content), 0o644); err != nil {
		t.Fatalf("failed to write agent changes: %v", err)
	}

	err = s.SaveChanges(SaveContext{
		SessionID:      sessionID,
		ModifiedFiles:  []string{"test.go"},
		NewFiles:       []string{},
		DeletedFiles:   []string{},
		MetadataDir:    metadataDir,
		MetadataDirAbs: metadataDirAbs,
		CommitMessage:  "Checkpoint 1",
		AuthorName:     "Test",
		AuthorEmail:    "test@test.com",
	})
	if err != nil {
		t.Fatalf("SaveChanges() checkpoint 1 error = %v", err)
	}

	// === USER PARTIAL STAGING SCENARIO ===
	// Step 1: User adds 5 lines to the file
	partialContent := testCheckpoint1Content + "// User added line 1\n// User added line 2\n// User added line 3\n// User added line 4\n// User added line 5\n"
	if err := os.WriteFile(testFile, []byte(partialContent), 0o644); err != nil {
		t.Fatalf("failed to write partial user content: %v", err)
	}

	// Step 2: User stages these 5 lines
	if _, err := worktree.Add("test.go"); err != nil {
		t.Fatalf("failed to stage partial changes: %v", err)
	}

	// Step 3: User adds 5 MORE lines to worktree (unstaged)
	// Now: staging area has 5 user lines, worktree has 10 user lines
	fullContent := partialContent + "// User added line 6\n// User added line 7\n// User added line 8\n// User added line 9\n// User added line 10\n"
	if err := os.WriteFile(testFile, []byte(fullContent), 0o644); err != nil {
		t.Fatalf("failed to write full user content: %v", err)
	}

	// === PROMPT 2 START: Initialize session again ===
	// This should capture ALL 10 worktree lines to match what WriteTemporary will capture
	if err := s.InitializeSession(sessionID, "Claude Code", "", ""); err != nil {
		t.Fatalf("InitializeSession() prompt 2 error = %v", err)
	}

	// Verify PendingPromptAttribution shows worktree changes (10 lines), not just staged (5 lines)
	state, err := s.loadSessionState(sessionID)
	if err != nil {
		t.Fatalf("loadSessionState() after prompt 2 error = %v", err)
	}

	if state.PendingPromptAttribution == nil {
		t.Fatal("PendingPromptAttribution is nil after prompt 2")
	}

	// Should count ALL 10 worktree lines, not just the 5 staged lines
	// This matches what WriteTemporary will capture in the checkpoint
	if state.PendingPromptAttribution.UserLinesAdded != 10 {
		t.Errorf("PendingPromptAttribution.UserLinesAdded = %d, want 10 (worktree lines, not just staged)",
			state.PendingPromptAttribution.UserLinesAdded)
	}

	if state.PendingPromptAttribution.CheckpointNumber != 2 {
		t.Errorf("PendingPromptAttribution.CheckpointNumber = %d, want 2",
			state.PendingPromptAttribution.CheckpointNumber)
	}

	// === Verify checkpoint captures the same content ===
	// This demonstrates why we need to read from worktree: the checkpoint will capture
	// the full worktree content (10 lines), so PromptAttribution must also count 10 lines
	err = s.SaveChanges(SaveContext{
		SessionID:      sessionID,
		ModifiedFiles:  []string{"test.go"},
		NewFiles:       []string{},
		DeletedFiles:   []string{},
		MetadataDir:    metadataDir,
		MetadataDirAbs: metadataDirAbs,
		CommitMessage:  "Checkpoint 2",
		AuthorName:     "Test",
		AuthorEmail:    "test@test.com",
	})
	if err != nil {
		t.Fatalf("SaveChanges() checkpoint 2 error = %v", err)
	}

	// Reload state to see final PromptAttributions
	state, err = s.loadSessionState(sessionID)
	if err != nil {
		t.Fatalf("loadSessionState() after checkpoint 2 error = %v", err)
	}

	// PromptAttributions should now contain the entry with 10 user lines
	if len(state.PromptAttributions) != 2 {
		t.Fatalf("expected 2 PromptAttributions, got %d", len(state.PromptAttributions))
	}

	// Second attribution (from prompt 2) should show 10 user lines
	attr2 := state.PromptAttributions[1]
	if attr2.UserLinesAdded != 10 {
		t.Errorf("PromptAttributions[1].UserLinesAdded = %d, want 10 (worktree content)",
			attr2.UserLinesAdded)
	}
}

// TestPromptAttribution_UnstagedChanges tests that unstaged changes are
// still read from the worktree (not the staging area).
func TestPromptAttribution_UnstagedChanges(t *testing.T) {
	dir := t.TempDir()
